-- W1.6 questions batch 6361/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-f0899a01-moex-00326', 'judicial-f0899a01', 'judicial-f0899a01-moex-111-9a3b44c4', 'sub-judicial-f0899a01-01', NULL, 'essay', '甲、乙為夫妻，一日乙在兩人住處（該屋由乙所承租）吵架時遭甲毆打，
乙遂報警前來處理。警員 A 到場後，乙除向 A 陳述甲之家暴行為外，更
主動向 A 說出甲持有非法槍械之情事。乙在簽立 A 出具之自願受搜索同
意書後，並帶同A入內在住處之客廳電視櫃抽屜內，搜出甲所有之槍枝與
子彈，A當場扣押該槍枝與子彈。甲則全程在場觀看，並未為任何表示，
僅坦承槍枝與子彈為其所有。試問，A之搜索行為是否合法？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "2bef7e63c6f0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "202", "s": "0515", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00327', 'judicial-f0899a01', 'judicial-f0899a01-moex-111-9a3b44c4', 'sub-judicial-f0899a01-01', NULL, 'essay', '甲因涉嫌竊取乙之財物，遭檢察官以涉犯竊盜罪提起公訴。本案受命法
官 A 考量近日疫情嚴重，乙於審判期日時如果確診或遭隔離而不能到
場，審判程序將無法進行，因此在行準備程序時即先行訊問乙。嗣後於
審判期日時，合議庭又考量乙雖同時為被害人，但既經訊問完畢，已無
再行傳喚到庭之必要，因此僅傳喚被告甲到庭，並未傳喚乙到庭。上述
對乙之訊問及未傳喚等程序是否合法？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "2bef7e63c6f0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "202", "s": "0515", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00328', 'judicial-f0899a01', 'judicial-f0899a01-moex-111-9a3b44c4', 'sub-judicial-f0899a01-01', NULL, 'essay', '甲為知名政論節目主持人，因在節目中指控政治人物 A貪贓枉法，被 A
向管轄之臺北地方法院提起誹謗罪之自訴。本案經臺北地方法院審理
後，判決甲無罪。A不服該判決，向臺灣高等法院提起上訴，經臺灣高
等法院審理後，認定甲之行為構成誹謗罪，撤銷原無罪判決，判決甲有
罪。甲不服臺灣高等法院之有罪判決，向最高法院提起上訴（上訴一）。
最高法院隨後撤銷該有罪判決，發回臺灣高等法院。經臺灣高等法院進
行更一審程序後，再次對甲為有罪判決。甲仍不服此一有罪判決，再向
最高法院提起上訴（上訴二）。試問甲之前、後兩次上訴（上訴一、二）
是否合法？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "2bef7e63c6f0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "202", "s": "0515", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00329', 'judicial-f0899a01', 'judicial-f0899a01-moex-111-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '關於罪刑法定原則，下列敘述何者正確？', '["保安處分並非刑罰，故不適用罪刑法定原則", "在有利於行為人時，可例外容許類推適用", "刑法未規定處罰之行為，可適用習慣法予以定罪", "沒收屬對物保安處分，故適用最有利於行為人之法律"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00330', 'judicial-f0899a01', 'judicial-f0899a01-moex-111-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '下列何者不成立刑法第185條之3危險駕駛罪？', '["甲酒後血液中酒精濃度達百分之零點一而駕駛公車", "甲吸食安非他命致不能安全駕駛而駕駛汽車", "甲一邊騎乘機車一邊吃泡麵", "甲吃完燒酒雞呼氣酒精濃度達每公升0.35毫克而騎機車回家"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00331', 'judicial-f0899a01', 'judicial-f0899a01-moex-111-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '有關空白刑法及其補充法令之變更的敘述，下列何者錯誤？', '["補充法令之內容僅涉及法律效果，無關犯罪之成立要件", "補充法令有變更時，實務見解認為無刑法第2條第1項之適用", "刑法第192條違背預防傳染病所公布之檢查或進口法令罪，屬空白刑法", "刑法第251條第1項第3款囤積行政院公告之生活必需用品而不應市銷售罪，屬空白刑法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00332', 'judicial-f0899a01', 'judicial-f0899a01-moex-111-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '關於刑法第305條之恐嚇危安罪，下列敘述何者正確？', '["以散布裸照之事要脅他人，依實務見解不構成刑法第305條之罪", "以神鬼迷信之事恐嚇他人，依實務見解不構成刑法第305條之罪", "刑法第305條之罪之成立，以行為人確有實施加害行為為必要", "刑法第305條之罪為保護健康法益之犯罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00333', 'judicial-f0899a01', 'judicial-f0899a01-moex-111-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '甲搭乘捷運，離開捷運站時，發現身後有乙尾隨，甲誤以為乙要行搶，因此在乙靠近甲時，甲反手毆 打乙一拳，致乙受傷，事後發現，乙只是路人而已。有關本案的錯誤類型，何者正確？', '["客體錯誤", "打擊錯誤", "容許構成要件錯誤", "包攝錯誤"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00334', 'judicial-f0899a01', 'judicial-f0899a01-moex-111-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '甲持刀砍殺乙，已經砍了三刀非致命部分，過程中乙不斷向甲求饒，甲原不予理會，但突然聽到警車 經過聲響，擔心被捕而罷手，乙因而逃過一死。有關此情形，下列敘述何者錯誤？', '["甲之罷手並非出於自主動機，故不屬出於己意", "甲成立殺人罪之障礙未遂犯", "依刑法規定，甲應減輕或免除其刑", "甲之侵害情狀僅達未了未遂之階段"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00335', 'judicial-f0899a01', 'judicial-f0899a01-moex-111-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '關於未遂犯，下列敘述何者正確？', '["未遂犯之處罰，應按既遂犯之刑減輕之", "甲基於殺乙的意思，朝乙開槍未中，甲僅成立殺人預備犯", "幻覺犯亦屬於未遂犯", "中止犯屬於未遂犯"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL)
